INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L4_A', 'G2e', 4, 'A', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Draw three completely different shapes that ALL have a perimeter of 12 cm.''', 'Draws varied polygons (e.g., 3x3 square, 4x2 rectangle, 5+4+3 triangle) where sides sum to 12.', 'Draws shapes without checking the sum.', 'How did you make sure the string going around them would be exactly 12 for all of them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L4_B', 'G2e', 4, 'B', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Design a garden where the perimeter is exactly 20 meters, but it is NOT a square.''', 'Designs a rectangle (e.g., 6x4) or another shape where sides sum to 20.', 'Cannot break away from the square (5x5) or gets the sum wrong.', 'If the top is 7m, what MUST the other sides be to make exactly 20m?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L4_C', 'G2e', 4, 'C', 'Design', NULL, NULL, NULL, NULL, NULL, 'Say: ''Write a word problem about building a fence for a goat. The person solving it has to find the perimeter to get the right amount of fence.''', 'Writes a problem defining the side lengths of an area and asks for total boundary length.', 'Writes an area problem or forgets to ask a question.', 'Why is a fence a perimeter problem and not an area problem?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L4_M', 'G2e', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Uncle wants to put a new wooden frame around his rectangular picture. The picture is 10 hands wide and 15 hands long. He has a piece of wood that is 40 hands long. Is it enough?', 'Child calculates the perimeter (10+15+10+15 = 50) and realizes 40 is not enough.', 'Only adds 10+15 and says yes.', 'If he only uses 25 hands of wood, what parts of the picture won''t have a frame?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L1_A', 'G2f', 1, 'A', 'Physical covering', 'A book, identical playing cards or small square tiles', NULL, NULL, NULL, NULL, 'Ask the child: ''How many cards do we need to completely cover the front of this book without leaving any spaces?''', 'Lays out the cards in a grid, covering the surface with no gaps or overlaps. Counts the total.', 'Leaves gaps, overlaps cards, or only lines the edges.', 'Why can''t we leave spaces between the cards if we want to know how big the cover is?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L1_B', 'G2f', 1, 'B', 'Physical covering', 'Two pieces of paper (one long skinny, one short fat), small blocks', NULL, NULL, NULL, NULL, 'Say: ''Which piece of paper is bigger? Let''s prove it by seeing how many blocks it takes to cover each one.''', 'Uses the blocks as a standard unit of area to compare two different shapes.', 'Guesses based on length alone without covering.', 'Even though this one is longer, why did the other one need more blocks?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L1_C', 'G2f', 1, 'C', 'Physical covering', 'Grid paper, crayons', NULL, NULL, NULL, NULL, 'Draw a large rectangle on the grid paper. Say: ''Color the inside of this shape. Count how many little squares you colored.''', 'Colors the interior and counts the squares, understanding that area is the 2D space inside.', 'Only colors the outline (perimeter).', 'What is the difference between coloring the line around the shape, and coloring the squares inside?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L2_A', 'G2f', 2, 'A', 'Counting area', NULL, NULL, NULL, NULL, NULL, 'Show a picture of a rectangle drawn on a grid. Ask the child to find the area by counting the squares.', 'Accurately counts all the squares inside the boundary.', 'Miscounts, or counts the perimeter lines.', 'Is there a faster way to count them instead of 1 by 1? (Looking for rows/columns).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L2_B', 'G2f', 2, 'B', 'Counting area', NULL, NULL, NULL, NULL, NULL, 'Show an irregular shape made of straight lines on a grid (like a cross or stairs). Ask for the area.', 'Carefully counts all the full squares.', 'Tries to multiply length x width on a shape that isn''t a rectangle.', 'Why can''t we just multiply the sides on this shape?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L2_C', 'G2f', 2, 'C', 'Array connection', NULL, NULL, NULL, NULL, NULL, 'Show a 3x4 rectangle on a grid. Ask: ''How many squares? Can you write a multiplication equation for this?''', 'Connects the concept of area to the array model of multiplication (3 x 4 = 12).', 'Just counts by 1s and cannot write the equation.', 'How does knowing your times tables help you find the area faster?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L3_A', 'G2f', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a rectangle covered with coins, but there are big gaps between the coins. Someone says ''The area is 10 coins.'' Is that accurate?', 'Explains that area requires covering the surface completely. Circles leave gaps, so they are bad for measuring area.', 'Agrees the area is 10.', 'Why do we use squares to measure area instead of circles?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L3_B', 'G2f', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show two shapes on a grid. A 4x4 square, and a 8x2 rectangle. Ask: ''My friend says the square is bigger because it''s taller. Is she right?''', 'Calculates the area of both (16) and proves they take up the exact same amount of space.', 'Agrees the square is ''bigger''.', 'Can two shapes look totally different but use the same amount of paint to cover?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L3_C', 'G2f', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Draw a shape on a grid and count the perimeter. Say: ''The area is 14.''', 'Corrects the error: you counted the lines around the outside, not the squares inside.', 'Agrees with the perimeter count as area.', 'If we were building a house, what is the perimeter, and what is the area?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L4_A', 'G2f', 4, 'A', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Draw a house on grid paper. Make sure the area of the house is exactly 24 squares.''', 'Creates a composite shape (e.g., rectangle with a triangle roof) where the total interior is 24 units.', 'Draws a house without counting, or counts the perimeter.', 'How did you keep track of the squares to make sure you didn''t go over 24?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L4_B', 'G2f', 4, 'B', 'Design', NULL, NULL, NULL, NULL, NULL, 'Say: ''I want to build a rectangular dog pen with an area of 12 squares. Draw all the different ways I could build it.''', 'Draws 1x12, 2x6, and 3x4 rectangles.', 'Only finds one way.', 'Which of these pens would give the dog the most room to run in a straight line?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L4_C', 'G2f', 4, 'C', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Explain the difference between perimeter and area to someone who has never heard those words before.''', 'Uses a clear real-world analogy (e.g., perimeter is the fence, area is the grass).', 'Uses confusing math jargon or gets them mixed up.', 'If I want to put a carpet in my room, do I need to know the area or the perimeter?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2f_L4_M', 'G2f', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'We spilled juice all over the table! We need to wipe it up. Should we use the long piece of string or the flat towel? Why?', 'Child chooses the towel because it covers a surface (area), while the string only covers a line.', 'Chooses the string because it is long.', 'Can a string cover the whole spill at the exact same time?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L1_A', 'G2g', 1, 'A', 'Physical folding', 'Paper cutouts of shapes (square, circle, irregular triangle)', NULL, NULL, NULL, NULL, 'Say: ''Fold these shapes in half so that both sides match perfectly. Which ones work and which ones don''t?''', 'Folds the symmetrical shapes correctly to demonstrate matching halves. Cannot fold the irregular triangle perfectly.', 'Folds the shapes randomly without matching the edges.', 'Why does the circle fold perfectly, but the weird triangle leaves parts sticking out?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L1_B', 'G2g', 1, 'B', 'Physical creation', 'Paint, paper', NULL, NULL, NULL, NULL, 'Have the child paint a design on one half of a piece of paper. Fold the paper in half and press down. Open it up. Ask: ''What happened to the painting?''', 'Observes that folding creates an exact mirror image on the other side.', 'Smears the paint without noticing the reflection.', 'If you drew a bird wing on one side, what would happen on the other side when you fold it?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L1_C', 'G2g', 1, 'C', 'Physical exploration', 'A small mirror, various pictures or objects', NULL, NULL, NULL, NULL, 'Put a mirror straight down the middle of a picture of a face, or a butterfly. Ask: ''Does the mirror show the whole picture or something different?''', 'Uses the mirror to find the line of symmetry where the reflection completes the original image perfectly.', 'Cannot align the mirror properly.', 'What happens if you put the mirror across the butterfly''s wing instead of its body?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L2_A', 'G2g', 2, 'A', 'Identifying symmetry', NULL, NULL, NULL, NULL, NULL, 'Show drawings of a heart, a capital ''A'', a capital ''R'', and a star. Ask the child to draw the line of symmetry on the ones that have it.', 'Correctly draws the vertical line on the heart and ''A''. Recognizes ''R'' has none.', 'Draws a line on ''R'', or draws horizontal lines on ''A''.', 'How can you check if your line is in the right place? (Imagine folding it).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L2_B', 'G2g', 2, 'B', 'Identifying symmetry', NULL, NULL, NULL, NULL, NULL, 'Show half a drawing on a grid (e.g., half a house). The line of symmetry is drawn. Ask the child to complete the drawing on the other side.', 'Mirrors the drawing accurately across the line.', 'Copies the drawing exactly instead of mirroring it (e.g., drawing two left halves).', 'If the roof goes UP and to the LEFT on this side, where does it go on the other side?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L2_C', 'G2g', 2, 'C', 'Identifying symmetry', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Find 3 things in this room that are symmetrical. Show me where the line is.''', 'Identifies symmetrical objects (e.g., a chair, a window, a face) and traces the center line.', 'Picks asymmetrical objects (like a shoe facing sideways).', 'Is a shoe symmetrical by itself? What about a PAIR of shoes?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L3_A', 'G2g', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a rectangle with a diagonal line drawn from corner to corner. Someone says: ''This is a line of symmetry because both sides are the same triangle.'' Is that right?', 'Explains that while they are the same triangle, folding them on that line does not make them match up perfectly (the points stick out).', 'Agrees it is a line of symmetry.', 'If you actually folded a piece of paper on that line, what would it look like?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L3_B', 'G2g', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a picture of a face with a mole on one cheek. The line of symmetry is drawn down the nose. Ask: ''Is this perfectly symmetrical?''', 'Notices the mole breaks the symmetry.', 'Ignores the small detail and says it''s symmetrical.', 'What has to happen for something to be PERFECTLY symmetrical?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2g_L3_C', 'G2g', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a drawing of an arrow pointing right. A vertical line is drawn through the middle. Is it a line of symmetry?', 'Explains no, because the left side is flat and the right side is pointy.', 'Guesses yes.', 'Where would you draw the line so that both halves DO match?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
