INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L4_C', 'P2a', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''You need to figure out which drawer in the kitchen has the most things in it. Tell me your step-by-step plan.''', 'Child explains a process of opening each drawer, counting the items, writing down the total for each, and then comparing the numbers.', 'Child guesses based on drawer size, or doesn''t include a recording step.', 'Why is it important to write the numbers down instead of just trying to remember them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L4_M', 'P2a', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'We are going to the store to buy snacks for the family movie night. How do we make sure we get something everyone actually wants to eat, without just guessing?', 'Child suggests asking everyone what they want and writing it down (taking a survey/collecting data).', 'Child just lists things they personally like, or says ''buy everything''.', 'If two people want the same thing, how do we make sure we get enough?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L1_A', 'P2b', 1, 'A', 'Physical bar graph', 'Blocks, books', NULL, NULL, NULL, NULL, 'Put 3 red blocks, 5 blue blocks, and 2 yellow blocks on the table. Say: ''Stack the blocks by color to see which color makes the tallest tower.''', 'Child physically stacks the blocks and visually compares the heights.', 'Child mixes the colors, or can''t see the connection between tower height and quantity.', 'Without counting the blocks, which color has the most? How do you know?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L1_B', 'P2b', 1, 'B', 'Physical tally marks', 'Popsicle sticks, pencils', NULL, NULL, NULL, NULL, 'Give the child a bunch of sticks. Say: ''We need to count these. Put down one stick for every finger on one hand. Then put another stick across them. This is a group of 5.''', 'Child arranges sticks into a tally group of 4 straight lines and 1 diagonal line.', 'Child makes a group of 5 parallel lines, or random piles.', 'Why is grouping sticks like this faster than just putting them in a straight line?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L1_C', 'P2b', 1, 'C', 'Physical bar graph', 'Coins, buttons', NULL, NULL, NULL, NULL, 'Say: ''Line up all the big coins in a row starting at this line. Now line up the small coins next to them. Let''s see which line goes further.''', 'Child creates parallel lines of objects to compare lengths visually.', 'Child makes lines of unequal starting points or spaces the items inconsistently.', 'Why do the lines need to start at exactly the same place to be fair?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L2_A', 'P2b', 2, 'A', 'Tally reading', NULL, NULL, NULL, NULL, NULL, 'Show a picture of tally marks (e.g., 3 groups of five, plus 2). Say: ''How many marks are here?''', 'Child correctly identifies the tally marks representing 17, preferably by counting 5, 10, 15, 16, 17.', 'Child counts every single mark by 1s, or misinterprets the cross line.', 'How does the slanted line help you count faster?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L2_B', 'P2b', 2, 'B', 'Graph reading', NULL, NULL, NULL, NULL, NULL, 'Show a simple bar graph (e.g., Cats: 4, Dogs: 6). Say: ''Look at the bar for Dogs. How many people chose Dogs?''', 'Child correctly reads the value 6 from the axis aligned with the top of the bar.', 'Child guesses, or counts the boxes incorrectly if there''s a scale.', 'How do you use the numbers on the side to find out how tall the bar is?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L2_C', 'P2b', 2, 'C', 'Graph creation', NULL, NULL, NULL, NULL, NULL, 'Say: ''I have 3 red apples and 5 green apples. Draw a bar graph to show this. Make sure the bars start at the bottom.''', 'Child draws two bars, labeling one Red and one Green, with the Green bar noticeably taller.', 'Child draws the bars sideways or floating, or makes them the same height.', 'If I get 3 more red apples, what will you have to do to your drawing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L3_A', 'P2b', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a bar graph where the numbers on the side skip around (1, 5, 2, 8). Say: ''What is wrong with the numbers on the side of this graph?''', 'Child identifies that the scale is out of order, making the bar heights meaningless.', 'Child thinks the numbers just show the exact values of the bars.', 'Why must the numbers on the side go in order like a ruler?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L3_B', 'P2b', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show tally marks: IIII I. Say: ''My friend tried to make a group of 5, but didn''t put the line across. Is this still 5?''', 'Child understands it represents 5 items, but points out it''s not the correct way to make a tally bundle for easy counting.', 'Child thinks it represents 6, or that it''s wrong because it doesn''t look like a bundle.', 'If you have a lot of marks, why is it better to put the line across instead of just leaving a space?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L3_C', 'P2b', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show two bar graphs. Graph 1 has a tall bar for 3 (each line is 1). Graph 2 has a short bar for 50 (each line is 10). Say: ''Which number is bigger? But which bar is taller? Why?''', 'Child explains that the tallness depends on the numbers on the side (the scale), not just the number of items.', 'Child insists the taller bar always means more items.', 'If you want to trick someone into thinking 3 is bigger than 50, how would you draw the graph?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L4_A', 'P2b', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Create a tally chart to show how many shirts, pants, and socks you are wearing right now.''', 'Child correctly identifies and records the quantities using tally marks.', 'Child uses numbers instead of tallies, or miscounts.', 'If you put on a jacket, how would you update your chart?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L4_B', 'P2b', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''I want you to make a bar graph showing the favorite colors of 4 imaginary friends. You decide the colors and the numbers. Make sure one color is a tie with another.''', 'Child creates a complete graph with labels, an ordered scale, and two bars of equal height.', 'Child forgets labels, scale, or doesn''t include a tie.', 'How can someone tell just by looking at the graph that there is a tie, without reading the numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L4_C', 'P2b', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Teach me how to read a bar graph using a drawing of two towers.''', 'Child explains that the taller tower means more, and shows how to check the numbers on the side.', 'Child just says ''the big one wins'' without explaining how to read the actual values.', 'What do the words at the bottom of the towers tell us?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L4_M', 'P2b', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'You are counting passing cars: 12 red, 15 blue, and 8 white. What is the fastest way to write this down quickly while they drive by, so you don''t lose count?', 'Child suggests using tally marks.', 'Child suggests writing full words or trying to remember them all.', 'Why are tally marks faster than writing the number ''12'' and then erasing it to write ''13''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L1_A', 'P2c', 1, 'A', 'Physical matching', '3 different items (e.g., shoe, spoon, book), 3 sticky notes (labels)', NULL, NULL, NULL, NULL, 'Put the items out with sticky notes saying: ''Size 6'', ''Silver'', ''100 pages''. Ask: ''Which question goes with each item? A) How long is it to read? B) What color is it? C) Will it fit my foot?''', 'Child correctly matches the item, its property, and the corresponding question.', 'Child mismatches properties and items, or cannot identify the correct question.', 'Why does ''100 pages'' answer ''How long is it to read'' and not ''Will it fit my foot''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L1_B', 'P2c', 1, 'B', 'Physical data translation', 'A small pile of 4 rocks and 2 leaves', NULL, NULL, NULL, NULL, 'Show the pile. Say: ''I have 4 rocks and 2 leaves. What is a question you could ask where the answer is 4?''', 'Child asks a question like ''How many rocks are there?''', 'Child asks ''How many leaves?'' or ''What are these?''', 'If the answer was 6, what question would you have asked?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L1_C', 'P2c', 1, 'C', 'Physical data translation', 'A jar of water', NULL, NULL, NULL, NULL, 'Hold up the jar. Say: ''The answer is "Half full." What was the question?''', 'Child asks ''How full is the jar?'' or ''How much water is in the jar?''', 'Child asks ''Is it water?'' or ''Is it empty?''', 'If the answer was ''Water,'' what would the question be?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L2_A', 'P2c', 2, 'A', 'Question identification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Here is some data: 12 people took the bus, 5 people walked, 3 people rode bikes. Which of these questions does this data answer? A) What is the most popular color? B) How do people get to work? C) How many cars are there?''', 'Child correctly identifies option B.', 'Child chooses A or C.', 'Why doesn''t this data answer question C?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L2_B', 'P2c', 2, 'B', 'Question generation', NULL, NULL, NULL, NULL, NULL, 'Say: ''The answer is 7. The data is: 3 boys and 4 girls. What is the question?''', 'Child formulates a question like ''How many children are there in total?''', 'Child asks ''How many girls?'' or doesn''t use the provided data.', 'How did you know the question was asking for the total?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L2_C', 'P2c', 2, 'C', 'Question identification', NULL, NULL, NULL, NULL, NULL, 'Show a simple bar graph with only two bars: ''Apples (6)'' and ''Oranges (4)''. Say: ''Tell me two different questions this graph can answer.''', 'Child asks ''Which fruit is more popular?'' and ''How many people like apples?'' or similar.', 'Child asks questions not covered by the graph, like ''Are the apples red?''', 'Can this graph tell us if they liked bananas? Why not?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L3_A', 'P2c', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''My friend collected data on the ages of everyone in our class. Then they said, "This proves that our class loves pizza the most." Why are they wrong?''', 'Child explains that age data cannot answer a question about food preferences.', 'Child agrees with the friend, or is confused.', 'What kind of data would you need to collect to prove what the class loves to eat?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L3_B', 'P2c', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''I want to know who the fastest runner is. So I measured how tall everyone is. Did I answer my question? Why?''', 'Child explains that height does not equal speed, so the data doesn''t answer the question.', 'Child thinks tall people are always faster.', 'What should I have measured instead?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L3_C', 'P2c', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a list: ''Apples: 5, Bananas: 3''. Say: ''Someone looked at this and asked: Are the apples red or green? Can this list tell them? Why?''', 'Child explains the list only gives the number of apples, not their color.', 'Child assumes a color based on the fruit name.', 'If you wanted to know the color, how would you change the list?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L4_A', 'P2c', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Think of a question about our family that you don''t know the answer to. Tell me the question, and then tell me exactly what data you would need to collect to answer it.''', 'Child formulates a measurable question (e.g., ''Who sleeps the longest?'') and an appropriate data collection method (recording sleep times).', 'Child asks an unmeasurable question (''Who is the best?''), or cannot link it to data.', 'If you collected the data and two people had the exact same answer, what does that tell you?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L4_B', 'P2c', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Create a short list of data (just 3 numbers and labels) that answers the question: What is the most common shoe size in this house?''', 'Child creates relevant data, e.g., ''Size 3: 2 pairs. Size 8: 1 pair. Size 10: 1 pair.''', 'Child lists random items or numbers unrelated to shoe sizes.', 'Why must you include the labels (like ''Size 3'') and not just the numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L4_C', 'P2c', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Teach me why we need to ask the RIGHT question before we start counting things.''', 'Child explains that if you count the wrong things (like counting colors when you want to know sizes), your numbers are useless.', 'Child cannot articulate the connection between the goal and the method.', 'Can you give me an example of counting the wrong thing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L4_M', 'P2c', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'We found a box of old keys. You want to figure out which room has the most doors. Can counting these keys tell you that?', 'Child realizes keys do not equal doors, and that the keys might go to locks, cars, or other houses. The data doesn''t answer the question.', 'Child assumes more keys means more doors.', 'What is the only way to truly find out which room has the most doors?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L1_A', 'P2d', 1, 'A', 'Physical grouping', 'A handful of coins or small mixed items, Paper', NULL, NULL, NULL, NULL, 'Put the coins in a pile. Say: ''Sort these by size. Which pile is the biggest? Without counting, just point to the group that has the most in it.''', 'Child visually identifies the largest group after sorting.', 'Child points to the largest coin instead of the largest group, or guesses without sorting.', 'If you put the biggest pile next to the smallest pile, what do you notice?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L1_B', 'P2d', 1, 'B', 'Physical grouping', 'Cards or pictures (e.g., 3 dogs, 1 cat, 4 birds)', NULL, NULL, NULL, NULL, 'Lay the cards out randomly. Say: ''Group all the same animals together. Which animal showed up the most often?''', 'Child correctly groups the cards and identifies the birds as the most frequent.', 'Child groups them incorrectly or guesses.', 'If I hide one bird card, which animal shows up the most often now?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L1_C', 'P2d', 1, 'C', 'Physical grouping', 'Mismatched socks from the laundry', NULL, NULL, NULL, NULL, 'Give the child a pile of socks (e.g., 5 white, 2 black, 1 striped). Say: ''Sort these by color. Which color do we have the most of right here?''', 'Child sorts by color and correctly identifies white as the most common.', 'Child tries to match pairs instead of grouping all similar colors, or guesses without sorting.', 'Why is it easier to find out which color is most common by sorting them first?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L2_A', 'P2d', 2, 'A', 'Finding mode from a list', NULL, NULL, NULL, NULL, NULL, 'Show a list of numbers: 2, 5, 2, 8, 2, 1. Say: ''Which number is in this list the most times?''', 'Child identifies 2 as the most frequent number.', 'Child points to 8 because it is the largest value, or guesses.', 'How can you prove that 2 is there more times than 5?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L2_B', 'P2d', 2, 'B', 'Finding mode from a tally chart', NULL, NULL, NULL, NULL, NULL, 'Show a tally chart: Apples (II), Bananas (IIII), Grapes (I). Say: ''Which fruit is the most popular according to the tallies?''', 'Child identifies Bananas by finding the category with the most tally marks.', 'Child counts incorrectly or picks the first item.', 'How did you know without counting every single mark?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L2_C', 'P2d', 2, 'C', 'Finding mode from a bar graph', NULL, NULL, NULL, NULL, NULL, 'Show a simple bar graph (e.g., Cats: 3, Dogs: 5, Birds: 2). Say: ''Which bar is the tallest? What animal does that bar stand for?''', 'Child identifies the tallest bar and reads the corresponding label (Dogs) at the bottom.', 'Child identifies the highest number on the axis rather than the category, or misreads the label.', 'If the Birds bar grew to be exactly as tall as the Dogs bar, which one would be the most popular?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L3_A', 'P2d', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a list: 3, 8, 3, 5, 3. Say: ''My friend says 8 is the most popular number because it is the biggest. Are they right? Why or why not?''', 'Child explains the difference between ''the biggest value'' and ''the value that appears most often''.', 'Child agrees with the friend.', 'Can you have a list where a tiny number like 1 is the most popular?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L3_B', 'P2d', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a list: 2, 4, 6, 8. Say: ''What number appears most often here?''', 'Child recognizes that all numbers appear exactly once, so there is no single number that appears most often.', 'Child picks a random number or the biggest one.', 'If I add another 4 to the list, what happens?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L3_C', 'P2d', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a tally chart where two categories tie: Red (III), Blue (III). Say: ''My friend says Red won because it is first on the list. Is that fair?''', 'Child explains that it is a tie because both have the same number of marks.', 'Child agrees because Red is listed first.', 'What would you have to do to break the tie?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L4_A', 'P2d', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Create a list of 5 numbers where 7 is the number that shows up the most often.''', 'Child generates a list like 7, 2, 7, 4, 7.', 'Child creates a list with no repeats, or where another number appears more often.', 'How could you change your list so that 7 is NO LONGER the number that shows up most often?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L4_B', 'P2d', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Imagine a race with 10 cars. Only red and blue cars are racing. Tell me a story about the cars crossing the finish line so that Red is the most common color to finish.''', 'Child creates a scenario where more than 5 red cars finish, e.g., ''6 red cars finish, and 4 blue cars finish.''', 'Child tells a story where blue wins or where the total is wrong.', 'If exactly 5 red and 5 blue cars cross the line, what happens to the most common color?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L4_C', 'P2d', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Draw a very simple bar graph with 3 bars where two of the bars tie for being the tallest.''', 'Child draws a graph with labels and ensures two bars are exactly the same height and taller than the third.', 'Child forgets labels, makes all bars different, or makes the tie shorter than the third bar.', 'If you asked one more person to vote, could there still be a tie?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L4_M', 'P2d', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'You are in charge of buying new shoes for your soccer team. You look at everyone''s current shoes: Size 4, Size 5, Size 4, Size 6, Size 4. You can only afford to buy ONE extra pair just in case someone''s breaks. What size should you buy and why?', 'Child identifies Size 4 because it is the most common size worn by the team.', 'Child picks the largest size, or a random size.', 'If three more kids join and they all wear Size 6, what size should you buy as the backup then?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L1_A', 'P2e', 1, 'A', 'Physical sorting', 'Cards with events (e.g., Sun rising, raining frogs, eating lunch)', NULL, NULL, NULL, NULL, 'Show the cards. Say: ''Sort these into two piles: Things that are very likely to happen tomorrow, and things that are very unlikely to happen tomorrow.''', 'Child correctly categorizes everyday events vs absurd or rare events.', 'Child thinks impossible events are likely, or puts everything in one pile.', 'Is ''raining frogs'' just unlikely, or is it actually impossible?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L1_B', 'P2e', 1, 'B', 'Physical sorting', 'A bag, 10 red blocks, 1 blue block', NULL, NULL, NULL, NULL, 'Put the blocks in the bag and shake it. Say: ''If I close my eyes and pull out one block, am I likely to get a red one or a blue one?''', 'Child identifies red as the likely outcome because there are many more of them.', 'Child guesses blue because it is their favorite color.', 'If I want to make pulling a blue block likely, what do I need to do to the bag?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L1_C', 'P2e', 1, 'C', 'Physical sorting', 'A spinner with unequal sections (e.g., 3/4 red, 1/4 blue)', NULL, NULL, NULL, NULL, 'Show the spinner. Say: ''Spin this 5 times. Before you spin, which color is more likely to win?''', 'Child predicts the larger section (red) will win.', 'Child thinks the small section is just as likely to win.', 'If you spin and it lands on blue, does that mean the spinner is broken?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);